-- ============================================================
-- MIGRATION 015: Master Jenis Surat (surat_types)
-- ============================================================
-- Tabel lookup: semua 74+ jenis surat dari SURAT_MASTER.
-- Data JSONB field dan DNA clauses disimpan agar admin bisa
-- lihat/matik satu surat tanpa perlu buka source code.
--
-- Sumber data: src/data/surat-master.ts + src/lib/letter-engine.ts
-- Dihasilkan oleh: python3 generate-surat-dna.py
-- ============================================================

-- Enable UUID
create extension if not exists "uuid-ossp";

-- ============================================================
-- Tabel: surat_types
-- ============================================================

create table if not exists public.surat_types (
  id               uuid primary key default uuid_generate_v4(),

  -- Identifier (unik, cocok dengan SURAT_MASTER key)
  code             text unique not null,

  -- Metadata dasar
  name             text not null,
  category         text not null,
  wewenang         boolean not null default true,
  description      text,
  eta              text default '1 hari kerja',
  kode_klasifikasi text,

  -- Flag surat "pengganti non-wewenang" (isNew: true di SURAT_MASTER)
  is_substitute    boolean not null default false,
  note             text,

  -- Field formulir spesifik — array of field keys
  -- FieldDef[] → [ {key, label, type, options?, required?, autofill?} ]
  -- Disimpan sebagai JSONB agar bisa dibaca oleh UI form builder
  form_fields      jsonb default '[]'::jsonb,

  -- DNA clause lines (string[] dari DNA_CLAUSES_PRESETS)
  dna_clauses       jsonb default '[]'::jsonb,

  -- Placeholder yang digunakan dalam DNA clauses
  dna_placeholders  text[] default '{}',

  -- Counts (for display)
  field_count       smallint default 0,
  dna_count         smallint default 0,

  -- Timestamps
  created_at        timestamptz not null default now(),
  updated_at        timestamptz
);

-- Trigger auto-update updated_at
drop trigger if exists surat_types_updated_at on public.surat_types;
create trigger surat_types_updated_at
  before update on public.surat_types
  for each row execute function public.handle_updated_at();

-- ============================================================
-- Indexes
-- ============================================================
create index if not exists surat_types_code_idx        on public.surat_types(code);
create index if not exists surat_types_category_idx    on public.surat_types(category);
create index if not exists surat_types_wewenang_idx     on public.surat_types(wewenang);
create index if not exists idx_surat_types_gin_fields   on public.surat_types using gin(form_fields);
create index if not exists idx_surat_types_gin_placeholders on public.surat_types using gin(dna_placeholders);

-- ============================================================
-- RLS Policies
-- ============================================================
alter table public.surat_types enable row level security;

-- Semua orang (anon + authenticated) bisa SELECT
-- karena data ini lookup table, tidak rahasia
create policy "surat_types_select"
  on public.surat_types
  for select
  using (true);

-- Hanya authenticated yang bisa INSERT/UPDATE/DELETE
-- (admin panel yang punya Supabase anon key)
create policy "surat_types_admin_mutate"
  on public.surat_types
  for insert
  with check (auth.role() = 'authenticated');

create policy "surat_types_admin_update"
  on public.surat_types
  for update
  using (auth.role() = 'authenticated');

create policy "surat_types_admin_delete"
  on public.surat_types
  for delete
  using (auth.role() = 'authenticated');

-- ============================================================
-- Helper function: get_surat_type
-- ============================================================
create or replace function public.get_surat_type(p_code text)
returns public.surat_types
language plpgsql
security definer
as $$
begin
  return (
    select * from public.surat_types
    where code = p_code
    limit 1
  );
end;
$$;

-- ============================================================
-- Helper function: list_surat_types_by_category
-- ============================================================
create or replace function public.list_surat_types_by_category(p_category text)
returns setof public.surat_types
language plpgsql
security definer
as $$
begin
  return query select * from public.surat_types
    where category = p_category
    order by name;
end;
$$;

-- ============================================================
-- Helper function: list_all_surat_types
-- ============================================================
create or replace function public.list_all_surat_types()
returns setof public.surat_types
language plpgsql
security definer
as $$
begin
  return query select * from public.surat_types
    order by category, name;
end;
$$;

